import{_ as a,o as t,c as i,ag as l}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Fielding Logger","description":"","frontmatter":{},"headers":[],"relativePath":"scoring-games/fielding-logger.md","filePath":"scoring-games/fielding-logger.md"}'),o={name:"scoring-games/fielding-logger.md"};function n(s,e,r,h,g,d){return t(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="fielding-logger" tabindex="-1">Fielding Logger <a class="header-anchor" href="#fielding-logger" aria-label="Permalink to &quot;Fielding Logger&quot;">​</a></h1><p>The Fielding Logger records defensive plays — who fielded the ball, how, and the result. This data drives fielding percentage, zone tendency charts, and throwing accuracy analytics.</p><h2 id="required-field-—-position" tabindex="-1">Required Field — Position <a class="header-anchor" href="#required-field-—-position" aria-label="Permalink to &quot;Required Field — Position&quot;">​</a></h2><p><strong>You must select a position before logging a fielding play.</strong> The position tells the analytics engine which player was responsible for the ball. If no position is selected the play cannot be saved.</p><h2 id="logging-a-fielding-play" tabindex="-1">Logging a Fielding Play <a class="header-anchor" href="#logging-a-fielding-play" aria-label="Permalink to &quot;Logging a Fielding Play&quot;">​</a></h2><ol><li>Select the <strong>fielder</strong> from the player selector</li><li>Select the <strong>position</strong> being played</li><li>Select the <strong>ball type</strong> — how the ball arrived</li><li>Select the <strong>fielding zone</strong> — where relative to the player the ball was hit</li><li>Select <strong>Catch</strong> or <strong>Error</strong> for the fielding result</li><li>If a throw was made select the <strong>throw zone</strong> and <strong>throw result</strong></li><li>Toggle <strong>Double Play</strong> if applicable</li><li>The record saves when you tap the throw result button</li></ol><h2 id="ball-types" tabindex="-1">Ball Types <a class="header-anchor" href="#ball-types" aria-label="Permalink to &quot;Ball Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Ground Ball</td><td>Ball hit on the ground</td></tr><tr><td>Line Drive</td><td>Ball hit on a line</td></tr><tr><td>Fly Ball</td><td>Ball hit in the air</td></tr></tbody></table><h2 id="fielding-zones" tabindex="-1">Fielding Zones <a class="header-anchor" href="#fielding-zones" aria-label="Permalink to &quot;Fielding Zones&quot;">​</a></h2><p>The fielding zone grid shows 9 positions relative to the fielder:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Behind Left | Behind | Behind Right</span></span>
<span class="line"><span>Left        | Player | Right</span></span>
<span class="line"><span>Front Left  | Front  | Front Right</span></span></code></pre></div><p>Select where the ball was relative to the fielder when they fielded it.</p><h2 id="throw-zones" tabindex="-1">Throw Zones <a class="header-anchor" href="#throw-zones" aria-label="Permalink to &quot;Throw Zones&quot;">​</a></h2><p>The throw zone grid shows 9 directional zones for the throw:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>High Left | High  | High Right</span></span>
<span class="line"><span>Left      | Player| Right</span></span>
<span class="line"><span>Low Left  | Low   | Low Right</span></span></code></pre></div><p>Select the direction and height of the throw.</p><h2 id="special-plays" tabindex="-1">Special Plays <a class="header-anchor" href="#special-plays" aria-label="Permalink to &quot;Special Plays&quot;">​</a></h2><p><strong>Double Play (DP)</strong> — toggle before saving to mark the play as a double play. Does not save automatically — must still complete the throw result.</p><p><strong>Passed Ball (PB)</strong> — for catchers only. Toggle to mark a passed ball. This counts as an error in the catcher&#39;s fielding percentage calculation.</p><h2 id="automatic-navigation" tabindex="-1">Automatic Navigation <a class="header-anchor" href="#automatic-navigation" aria-label="Permalink to &quot;Automatic Navigation&quot;">​</a></h2><p>When a pitch is logged as <strong>Hit in Play</strong> in the Pitching Logger the app automatically navigates to the Fielding Logger. After logging the fielding play return to the Game Hub manually — multiple fielding plays can result from one ball in play (for example a bobble followed by a recovery throw).</p>`,21)])])}const u=a(o,[["render",n]]);export{c as __pageData,u as default};
